// Lookup table for the neighborhood names listed in koreaSnapshot.ts → days.
// Centroids + radii are visually-checked rough fits; polygons are GeoJSON
// outer-ring vertex lists fetched from OSM Nominatim (one-time enrichment
// at /tmp/fetch-polygons.ts; rerun if neighborhood names change). 8 of 30
// neighborhoods fell back to a synthetic 32-vertex circle around the
// centroid because Nominatim either had no admin record or only returned
// a Point/LineString geometry for that query.

export interface NeighborhoodCenter {
  name: string;
  lat: number;
  lng: number;
  /** Highlight radius in meters — used by clients that fall back to a
   *  flat disc render when the polygon is unavailable. */
  radiusM: number;
  /** Closed outer ring as [lng, lat][] (GeoJSON convention; first === last).
   *  Drawn by Map Mode as a terrain-conforming polygon highlight. */
  polygon: [number, number][];
}

/** Strip "(AM)" / "(PM)" / etc. suffixes from a day-snapshot name so the
 *  lookup matches the canonical entry. */
function canonicalize(name: string): string {
  return name.replace(/\s*\([^)]*\)\s*$/, "").trim();
}

